noncompliant:
namespace MyLib
{
    public class Foo
    {
        static int i;
        static string s;

        static Foo() // Noncompliant - static constructor only initializes fields
        {
            i = 3;
            ResourceManager sm = new ResourceManager("strings", Assembly.GetExecutingAssembly());
            s = sm.GetString("mystring");
        }
    }
}

compliant:
namespace MyLib
{
    public class Foo
    {
        static int i = 3; // Compliant - inline initialization
        static string s = InitString();

        static string InitString()
        {
            ResourceManager sm = new ResourceManager("strings", Assembly.GetExecutingAssembly());
            return sm.GetString("mystring");
        }
    }
}
